const products = $input.first().json;

const transformedProducts = products.map(product => {
  const variant = product.variants?.[0] || {};

  return {
    printify_id: product.id.toString(),
    name: product.title,
    category: mapCategory(product.title),
    description: product.description || '',
    price: variant.price ? variant.price / 100 : 0,
    image_url: product.images?.[0]?.url || '',
    brand: 'imperium',
    in_stock: product.variants?.some(v => v.available > 0) || false,
    printify_variant_id: variant.id?.toString() || ''
  };
});

function mapCategory(title) {
  const t = title.toLowerCase();
  if (t.includes('shirt') || t.includes('tee') || t.includes('t-shirt')) return 'shirts';
  if (t.includes('hoodie') || t.includes('sweatshirt')) return 'hoodies';
  if (t.includes('sweat') || t.includes('pants') || t.includes('jogger')) return 'sweats';
  if (t.includes('beanie')) return 'beanies';
  if (t.includes('hat') || t.includes('cap') || t.includes('snapback')) return 'hats';
  return 'shirts';
}

return transformedProducts;
